import bisect

class ConsistentHash:
    def __init__(self, vnodes=100):
        self.vnodes  = vnodes
        self.ring    = {}     # position -> node_name
        self.sorted_keys = []

    def _pos(self, key): return hash(key) % (2**32)

    def add_node(self, node):
        for i in range(self.vnodes):
            pos = self._pos(f'{node}#{i}')
            self.ring[pos] = node
            bisect.insort(self.sorted_keys, pos)

    def remove_node(self, node):
        for i in range(self.vnodes):
            pos = self._pos(f'{node}#{i}')
            del self.ring[pos]
            idx = bisect.bisect_left(self.sorted_keys, pos)
            self.sorted_keys.pop(idx)

    def get_node(self, key):
        if not self.ring:
            return None
        pos = self._pos(key)
        idx = bisect.bisect_right(self.sorted_keys, pos)
        idx = ___________   # wrap around the ring
        return self.ring[self.sorted_keys[idx]]
